'use client';

import { useEffect } from 'react';
import { RefreshCw, AlertTriangle } from 'lucide-react';

export default function DashboardError({
  error,
  reset,
}: {
  error: Error & { digest?: string };
  reset: () => void;
}) {
  useEffect(() => {
    console.error('Dashboard error boundary caught error:', error);
  }, [error]);

  return (
    <div className="flex min-h-[50vh] flex-col items-center justify-center text-center p-6 max-w-md mx-auto my-8">
      <div className="flex h-14 w-14 items-center justify-center rounded-[20px] bg-red-50 dark:bg-red-950/20 text-red-600 dark:text-red-400 border border-red-200/50 dark:border-red-900/30 mb-5 shadow-sm">
        <AlertTriangle size={24} />
      </div>
      
      <h2 className="text-lg font-black text-[var(--text-primary)] tracking-tight">Something went wrong</h2>
      <p className="text-xs text-[var(--text-secondary)] mt-2 mb-6 leading-relaxed">
        An error occurred while loading the dashboard components. Please attempt to reset the hydration cycle or refresh the portal.
      </p>

      <div className="flex items-center gap-3">
        <button
          onClick={() => reset()}
          className="btn-primary flex items-center gap-2 cursor-pointer"
        >
          <RefreshCw size={14} className="animate-spin-slow" />
          Reset Layout
        </button>
        <button
          onClick={() => window.location.reload()}
          className="btn-secondary cursor-pointer"
        >
          Refresh Portal
        </button>
      </div>
    </div>
  );
}
